code = response.strip()

# BETTER — extract first fenced block, or fall back to whole response
import re

def extract_code(response: str) -> str:
    # Try to find a fenced code block first
    match = re.search(r"```(?:python)?\n?(.*?)```", response, re.DOTALL)
    if match:
        return match.group(1).strip()
    # Fall back: if the response contains 'def ' it's probably raw code
    if "def " in response or "print(" in response:
        return response.strip()
    raise ValueError(f"No executable code found in model response: {response[:200]}")
